package skel.badgpt;

import java.io.File;
import java.io.FileNotFoundException;
import java.io.FileWriter;
import java.io.IOException;
import java.util.Scanner;

class Badgpt {
	static String string;
	static int MOD = 1000000007;

	Badgpt() {}

	static long[][] multiply(long[][] A, long[][] B) {
		int n = A.length;
		int m = A[0].length;
		int k = B[0].length;

		long[][] C = new long[n][k];

		for (int i = 0; i < n; i++) {
			for (int j = 0; j < k; j++) {
				for (int p = 0; p < m; p++) {
					C[i][j] += A[i][p] * B[p][j];
					C[i][j] %= MOD;
				}
			}
		}

		return C;
	}

	static long[][] pow(long[][] A, long p) {
		int n = A.length;

		long[][] result = new long[n][n];
		for (int i = 0; i < n; i++) {
			for (int j = 0; j < n; j++) {
				result[i][j] = (i == j) ? 1 : 0;
			}
		}

		while (p > 0) {
			if (p % 2 == 1) {
				result = multiply(result, A);
			}

			A = multiply(A, A);
			p /= 2;
		}

		return result;
	}

	// Function to calculate the nth Fibonacci number using matrix exponentiation
	static long fibo(long n) {
		long[][] base = {{0, 1}, {1, 1}};
		long[][] result = pow(base, n - 1);

		return result[1][0] + result[1][1];
	}
	static long badgpt(String string) {
		long fibon = 1;
		long fibom = 1;

		// If the input string does not contain any "n" or "u" characters, return 1
		if (!string.contains("n") && !string.contains("u")) {
			return 1;
		} else {
			// Iterate through the input string
			int i = 0;
			while (i < string.length()) {
				// If the current character is "n", extract the number of "n" characters that
				// follow and calculate the corresponding Fibonacci number
				if (string.charAt(i) == 'n') {
					String number_of_ns = "";
					while (i + 1 < string.length() && Character.isDigit(string.charAt(i + 1))) {
						number_of_ns += string.charAt(i + 1);
						i++;
					}

					long n = Long.parseLong(number_of_ns);
					fibon = (fibon * fibo(n)) % MOD;
					// If the current character is "u", extract the number of "u" characters that
					// follow and calculate the corresponding Fibonacci number
				} else if (string.charAt(i) == 'u') {
					String number_of_us = "";
					while (i + 1 < string.length() && Character.isDigit(string.charAt(i + 1))) {
						number_of_us += string.charAt(i + 1);
						i++;
					}

					long u = Long.parseLong(number_of_us);
					fibom = (fibom * fibo(u)) % MOD;
				}
				i++;
			}
		}

		// Multiply the calculated Fibonacci numbers and return the result modulo MOD
		return (fibon * fibom) % MOD;
	}

	public static void main(String[] args) {
		try {
			Scanner sc = new Scanner(new File("badgpt.in"));

			string = sc.nextLine();

			long ans = badgpt(string);

			try {
				FileWriter fw = new FileWriter("badgpt.out");
				fw.write(Long.toString(ans));
				fw.close();

			} catch (IOException e) {
				System.out.println(e.getMessage());
			}

			sc.close();
		} catch (FileNotFoundException e) {
			System.out.println(e.getMessage());
		}
	}
}
